import React from 'react'
import { css } from '@linaria/core'
import { ExpandableListItem, Ellipsis, ListItem, colors, List, ListSubSection } from '@fs/zion-ui'
import { baseUrl } from '@fs/zion-config'
import debugLib from '@fs/zion-debug'
import { useTranslation } from 'react-i18next'
import { trackLink, trackEvent } from '@fs/zion-analytics'
import useShowHelpOthers from '../dataHooks/useShowHelpOthers'
import { useNavigationContext } from '../shared/NavigationProvider/NavigationProvider'

const debug = debugLib('header2019:UserMobile')

const assignmentLabelStyle = css`
  font-weight: bold;
  font-size: 0.75em;
  margin-inline-end: 1em;
  top: -0.1em;
`

export default function UserMobile({
  profileName = '',
  portraitUrl,
  state = {},
  dispatch = () => {},
  activeRole,
  adminRoles = [],
  signOutReturnUrl,
  closeInfosheet = () => {},
  helpOthersOverlay,
  external = false,
}) {
  const showHelpOthers = useShowHelpOthers(adminRoles)
  const { t } = useTranslation()
  const avatarLetter = profileName[0]
  function handleAdminEnter(assignment) {
    if (assignment !== activeRole) {
      trackEvent({
        event_name: 'admin-role-enter',
      })
      import('@fs/zion-admin-mode')
        .then(({ enterRole }) => enterRole(null, assignment))
        .catch((error) => {
          debug('Admin Mode Error in UserMobile.js:', error)
        })
    }
  }

  const { accountNavigation } = useNavigationContext()

  const items = []
  accountNavigation?.sub?.forEach((sub) =>
    items.push(
      <ListItem
        key={sub.text}
        primaryText={sub.text}
        to={
          sub.id === 'sign_out'
            ? `${external && sub.url.startsWith('/') ? baseUrl : ''}${sub.url}${signOutReturnUrl}`
            : `${external && sub.url.startsWith('/') ? baseUrl : ''}${sub.url}`
        }
        onClick={() => {
          trackLink(null, sub.url, 'click_action', `hdr19_${accountNavigation.id}:${sub.id}`)
        }}
        target={sub.target}
        external
        dense
      />
    )
  )

  const roleItems = []
  if (showHelpOthers) {
    roleItems.push(
      <ListItem
        key="help-others"
        data-testid="hdr-help-others"
        onClick={() => {
          trackLink(null, 'click_action', `hdr19_help_others`)
          helpOthersOverlay.handleClick()
          closeInfosheet(false)
        }}
        primaryText={t('account.help-others.action', 'Help Others')}
        dense
      />
    )
  }
  if (adminRoles.length > 0) {
    adminRoles.forEach(({ assignment }) =>
      roleItems.push(
        <ListItem
          key={assignment}
          onClick={() => handleAdminEnter(assignment)}
          data-admin-role
          dense
          primaryText={
            <Ellipsis>
              <span style={assignment === activeRole ? { color: colors.red70 } : null}>
                <span className={assignmentLabelStyle}>ADM</span>
                {assignment}
              </span>
            </Ellipsis>
          }
        />
      )
    )
  }

  if (roleItems.length > 0) {
    items.push(
      <ListSubSection key="subsection" heading={t('header.menu.sublabel', 'Assist & Admin')}>
        {roleItems}
      </ListSubSection>
    )
  }

  return (
    <List>
      <ExpandableListItem
        open={state.userMobile}
        setOpen={(value) => dispatch({ key: 'userMobile', value: value(state.userMobile) })}
        emphasized
        primaryText={<Ellipsis>{profileName}</Ellipsis>}
        startElement={
          <ListItem.Avatar
            monogram={avatarLetter}
            src={portraitUrl}
            title={t('header.user.portrait.label', 'User Portrait')}
          />
        }
        noKeyline
      >
        {items}
      </ExpandableListItem>
    </List>
  )
}
